import { ActionPagePaymentConfiguration } from '@domain/actionPages';
import { InlineBillingAgreement } from '@domain/billingAgreement';
import { formatCurrency } from '@ui/utils/formatCurrency';
import { computeTotalFees } from '@utils/computeTotalFees';
import { hex2rgba } from '@utils/hex2rgba';
import clsx from 'clsx';
import { useMemo } from 'react';
import { useFormContext } from 'react-hook-form';
import { FormSingleCheckboxControl } from '../../../../../components/CheckboxControl/FormSingleCheckboxControl';
import { Heading } from '../../../../../components/Heading';
import { Label } from '../../../../../components/Label';
import { Meta } from '../../../../../components/Meta';

type Props = {
  actionElementColorPrimary?: string;
  amount?: number | null;
  billingAgreements?: InlineBillingAgreement[];
  cardType?: 'american-express' | 'american_express' | 'visa' | 'mastercard' | 'discover';
  feeCoverType: ActionPagePaymentConfiguration['feeCoverType'];
  pageType?: 'donation' | 'lead' | 'storefront' | 'event';
  paymentType?:
    | 'applepay'
    | 'googlepay'
    | 'paypal'
    | 'credit_card'
    | 'bank_account'
    | 'plaid_bank_account';
};

export const CoverTheFees = ({
  actionElementColorPrimary,
  amount,
  billingAgreements,
  cardType,
  feeCoverType,
  pageType,
  paymentType,
  ...props
}: Props) => {
  const { watch } = useFormContext();
  const customerCoversTheFees = pageType === 'storefront' ? true : watch('customerCoveredFees');
  const country = watch('addressAttributes.country');
  const promoCodeDiscount = watch('promoCodeDiscount');

  const totalFees = useMemo(
    () =>
      computeTotalFees({
        amount: Math.max((amount ?? 0) - (promoCodeDiscount ?? 0), 0),
        billingAgreements,
        cardType: !cardType || cardType === 'american_express' ? 'american-express' : cardType,
        isInternational: country !== 'US',
        paymentType,
      }),
    [amount, billingAgreements, cardType, country, paymentType, promoCodeDiscount]
  );

  if (feeCoverType !== 'opt_in' && feeCoverType !== 'opt_out' && feeCoverType !== 'required') {
    return null;
  }

  const backgroundColor =
    !!amount && !!totalFees
      ? customerCoversTheFees
        ? hex2rgba(actionElementColorPrimary, 0.2)
        : '#FEF5C7'
      : '#F1F2F4';

  const minHeight =
    customerCoversTheFees && feeCoverType !== 'required' ? 'min-h-[48px]' : 'min-h-[80px]';

  const feesText = totalFees ? formatCurrency(totalFees) : '';
  const amountText = amount ? formatCurrency(amount) : '';
  const coverTheFeesText = totalFees
    ? feeCoverType === 'required'
      ? `${feesText} will be added to cover the fees.`
      : `Add ${feesText} to cover the fees`
    : 'Cover the fees';

  const caption = (
    <Heading as="h4" className={!amount || !totalFees ? '!text-neutral-400' : undefined}>
      {!amount || !totalFees ? 'Cover the fees' : coverTheFeesText}
    </Heading>
  );

  return totalFees ? (
    <div
      className="mt-8 flex w-full flex-col items-center justify-center gap-4 rounded-md"
      {...props}
    >
      <div
        className={clsx(
          'ease flex w-full flex-col items-center justify-center rounded-md transition-all duration-200',
          minHeight
        )}
        style={{ backgroundColor }}
      >
        {!totalFees || !amount ? (
          caption
        ) : feeCoverType !== 'required' ? (
          <FormSingleCheckboxControl
            formControlProps={{ className: '!mb-0 !w-fit mx-auto' }}
            name="customerCoveredFees"
            variant="darkCheckbox"
          >
            <div className="ml-2 flex items-center">{caption}</div>
          </FormSingleCheckboxControl>
        ) : (
          caption
        )}
        {!customerCoversTheFees && amount ? (
          <Meta variant="regular">Final fees may be lower than shown.</Meta>
        ) : null}
      </div>
      {customerCoversTheFees && (!!totalFees || !!amount) ? (
        <div className="flex w-full justify-between">
          <div className="flex gap-1">
            <Label variant="regular">Amount:</Label>
            <Label variant="bold">{amountText}</Label>
          </div>
          <div className="flex gap-1">
            <Label variant="regular">Fees:</Label>
            <Label variant="bold">{feesText}</Label>
          </div>
        </div>
      ) : null}
    </div>
  ) : null;
};
